import React from 'react';
import { Member } from '../types';
import { User, Calendar, CreditCard, Activity, Phone, AlertTriangle, ArrowDownCircle, XCircle, Clock } from 'lucide-react';

interface Props {
  member: Member;
  onRenewClick: () => void;
}

const MemberCard: React.FC<Props> = ({ member, onRenewClick }) => {
  const isValid = member.status === 'Valid';
  const isExpired = member.status === 'Expired';

  const statusColor = isValid ? 'text-brand-success' : 'text-brand-danger';
  const borderColor = isValid ? 'border-brand-success' : 'border-brand-danger';
  const bgColor = isValid ? 'bg-green-900/10' : 'bg-red-900/10';

  // Calculate days remaining
  const today = new Date();
  const startDate = new Date(member.startDate);
  const expDate = new Date(member.expirationDate);

  const diffTime = expDate.getTime() - today.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

  // Show warning if valid and expiring within 30 days (and not already expired/invalid)
  const isExpiringSoon = isValid && !isNaN(diffDays) && diffDays <= 30 && diffDays >= 0;

  // Calculate Progress
  const totalDuration = expDate.getTime() - startDate.getTime();
  const elapsedDuration = today.getTime() - startDate.getTime();

  let progressPercentage = 0;
  if (totalDuration > 0) {
      progressPercentage = (elapsedDuration / totalDuration) * 100;
  }

  // Clamp percentage between 0 and 100
  progressPercentage = Math.min(Math.max(progressPercentage, 0), 100);

  // Bar Color Logic
  let barColor = 'bg-brand-accent';
  if (isExpired) barColor = 'bg-brand-danger';
  else if (isExpiringSoon) barColor = 'bg-yellow-500';
  else if (progressPercentage > 85) barColor = 'bg-yellow-500';

  return (
    <div className={`rounded-xl border ${borderColor} ${bgColor} p-6 shadow-lg backdrop-blur-sm relative overflow-hidden transition-all duration-300`}>

      {/* Expiring Soon Corner Badge */}
      {isExpiringSoon && (
        <div className="absolute top-0 right-0">
             <div className="bg-yellow-500 text-black text-xs font-bold px-3 py-1 rounded-bl-lg shadow-md flex items-center gap-1">
                <AlertTriangle className="w-3 h-3" />
                <span>Expiring Soon</span>
             </div>
        </div>
      )}

      {/* Expired Corner Badge */}
      {isExpired && (
        <div className="absolute top-0 right-0">
             <div className="bg-brand-danger text-white text-xs font-bold px-3 py-1 rounded-bl-lg shadow-md flex items-center gap-1">
                <XCircle className="w-3 h-3" />
                <span>Membership Expired</span>
             </div>
        </div>
      )}

      <div className="flex flex-col gap-6">

        {/* User Info Header */}
        <div className="flex items-center gap-3">
            <div className="p-2 bg-brand-dark rounded-full border border-slate-700">
               <User className="text-brand-accent w-6 h-6" />
            </div>
            <h2 className="text-2xl font-bold text-white">{member.name}</h2>
        </div>

        {/* Alerts */}
         {isExpiringSoon && (
           <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-lg bg-yellow-500/20 border border-yellow-500/40 text-yellow-300 text-sm font-medium animate-pulse">
              <AlertTriangle className="w-4 h-4" />
              <span>Subscription expires in {diffDays} days</span>
           </div>
         )}

         {isExpired && (
           <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-lg bg-red-500/20 border border-red-500/40 text-red-300 text-sm font-medium">
              <XCircle className="w-4 h-4" />
              <span>Your subscription has expired. Please renew.</span>
           </div>
         )}

        {/* Details Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-4 gap-y-3">
             <div className="flex items-center gap-2 text-slate-300">
                <Activity className="w-4 h-4 text-brand-accent" />
                <span className="font-medium text-slate-400">Package:</span>
                <span className="text-white">{member.package}</span>
             </div>
             <div className="flex items-center gap-2 text-slate-300">
                <CreditCard className="w-4 h-4 text-brand-accent" />
                <span className="font-medium text-slate-400">Amount:</span>
                <span className="text-white">{member.amount}</span>
             </div>
             <div className="flex items-center gap-2 text-slate-300">
                <Phone className="w-4 h-4 text-brand-accent" />
                <span className="font-medium text-slate-400">Phone:</span>
                <span className="text-white">{member.phone}</span>
             </div>
             <div className="flex items-center gap-2 text-slate-300">
                <Clock className="w-4 h-4 text-brand-accent" />
                <span className="font-medium text-slate-400">Status:</span>
                <span className={`font-bold ${statusColor}`}>{member.status}</span>
             </div>
        </div>

        {/* Progress Bar Section */}
        <div className="mt-2 bg-slate-900/50 p-4 rounded-xl border border-slate-700/50">
            <div className="flex justify-between text-xs text-slate-400 mb-2">
                <div className="flex flex-col">
                   <span className="font-medium text-slate-500">Start Date</span>
                   <span>{member.startDate}</span>
                </div>
                <div className="flex flex-col items-end">
                   <span className="font-medium text-slate-500">End Date</span>
                   <span>{member.expirationDate}</span>
                </div>
            </div>

            <div className="h-3 w-full bg-slate-800 rounded-full overflow-hidden shadow-inner">
                <div 
                    className={`h-full ${barColor} transition-all duration-1000 ease-out`}
                    style={{ width: `${progressPercentage}%` }}
                />
            </div>

            <div className="flex justify-between items-center mt-2">
                <span className="text-xs text-slate-400">
                    {isValid ? `${Math.floor(progressPercentage)}% Elapsed` : 'Terminated'}
                </span>
                <span className={`text-xs font-bold ${isExpiringSoon ? 'text-yellow-400' : isExpired ? 'text-red-400' : 'text-brand-accent'}`}>
                    {isExpired ? 'Expired' : `${diffDays} days left`}
                </span>
            </div>
        </div>

        {/* Action Button */}
        <div className="mt-2">
            <button 
              onClick={onRenewClick}
              className="bg-brand-accent hover:bg-brand-accentHover text-brand-black font-bold py-3 px-6 rounded-lg shadow-md hover:shadow-lg hover:shadow-brand-accent/20 transition-all duration-200 flex items-center gap-2 group w-full sm:w-auto justify-center"
            >
              <span>Renew Membership</span>
              <ArrowDownCircle className="w-5 h-5 group-hover:translate-y-1 transition-transform" />
            </button>
        </div>

      </div>
    </div>
  );
};

export default MemberCard;

