    // MODIFICATION: Simply overwrite the PIN to allow resets.
    sheet.getRange(foundRow, pinIndex + 1).setValue(hashedPin);

    return { success: true, message: 'PIN successfully updated' };

  } catch (error) {
    return { success: false, message: 'Server error: ' + error.toString() };
  }
}

function doPost(e) {
  try {
    const data = JSON.parse(e.postData.contents);
    const phone = data.phone;
    const action = data.action;

    if (action === 'setupPin') {
      return ContentService.createTextOutput(JSON.stringify(setupPin(phone, data.hashedPin))).setMimeType(ContentService.MimeType.JSON);
    } 
    else if (action === 'login') {
      return ContentService.createTextOutput(JSON.stringify(loginMember(phone, data.hashedPin))).setMimeType(ContentService.MimeType.JSON);
    }
    else if (action === 'saveNotificationToken') {
      return ContentService.createTextOutput(JSON.stringify(saveNotificationToken(data.phone, data.token))).setMimeType(ContentService.MimeType.JSON);
    }

    // Legacy support
    return ContentService.createTextOutput(JSON.stringify({success:false, message: "Invalid action or legacy request"})).setMimeType(ContentService.MimeType.JSON);

  } catch (error) {
    return ContentService.createTextOutput(JSON.stringify({success:false, message: error.toString()})).setMimeType(ContentService.MimeType.JSON);
  }
}
